INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'In Python, what is the output of: `def kadane(arr): max_so_far = max_ending_here = arr[0]; for x in arr[1:]: max_ending_here = max(x, max_ending_here + x); max_so_far = max(max_so_far, max_ending_here); return max_so_far; print(kadane([-2, 1, -3, 4, -1, 2, 1]))`?', ARRAY['3', '6', 'Optimizes disk I/O', 'Stateful: connection-aware, Stateless: rule-based'], '6', 1500, 90.0) ON CONFLICT DO NOTHING;
