INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'In C, what is the output of this KMP preprocessing: `void computeLPS(char *pat, int m, int *lps) { int len = 0, i = 1; lps[0] = 0; while(i < m) { if(pat[i] == pat[len]) { len++; lps[i++] = len; } else if(len > 0) len = lps[len-1]; else lps[i++] = 0; } } int lps[6]; computeLPS("AABAAC", 6, lps); printf("%d", lps[5]);`?', ARRAY['O(log n)', 'Precision: accuracy, Recall: coverage', '5', '0'], '0', 1500, 90.0) ON CONFLICT DO NOTHING;
