INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'In Python, what is the output of: `def edit_distance(s1, s2): m, n = len(s1), len(s2); dp = [[0]*(n+1) for _ in range(m+1)]; for i in range(m+1): dp[i][0] = i; for j in range(n+1): dp[0][j] = j; for i in range(1, m+1): for j in range(1, n+1): if s1[i-1] == s2[j-1]: dp[i][j] = dp[i-1][j-1]; else: dp[i][j] = min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]) + 1; return dp[m][n]; print(edit_distance("cat", "cut"))`?', ARRAY['O(V + E)', '7 12 (compiler-dependent)', 'Optimizes disk I/O', '1'], '1', 1500, 90.0) ON CONFLICT DO NOTHING;
INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'What is the time complexity of finding the longest palindromic substring using dynamic programming?', ARRAY['O(n²)', 'Category max prices and overall max price', 'O(b^d)', 'Precision: accuracy, Recall: coverage'], 'O(n²)', 1500, 90.0) ON CONFLICT DO NOTHING;
