INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'In Python, what is the output of: `def max_profit(prices): n = len(prices); if n < 2: return 0; dp = [0]*n; min_price = prices[0]; for i in range(1, n): min_price = min(min_price, prices[i]); dp[i] = max(dp[i-1], prices[i] - min_price); return dp[n-1]; print(max_profit([7, 1, 5, 3, 6, 4]))`?', ARRAY['14', '5', '4', 'O(m)'], '5', 1500, 90.0) ON CONFLICT DO NOTHING;
