INSERT INTO questions (subject, difficulty, question_text, options, correct_answer, question_elo, expected_time_seconds) VALUES ('Technical Aptitude', 'hard', 'In Python, what is the output of: `def count_inversions(arr): def merge_and_count(l, r): inv = 0; res = []; i = j = 0; while i < len(l) and j < len(r): if l[i] <= r[j]: res.append(l[i]); i += 1; else: res.append(r[j]); inv += len(l)-i; j += 1; res.extend(l[i:]); res.extend(r[j:]); return res, inv; def sort_and_count(arr): if len(arr) <= 1: return arr, 0; mid = len(arr)//2; l, inv_l = sort_and_count(arr[:mid]); r, inv_r = sort_and_count(arr[mid:]); merged, inv_m = merge_and_count(l, r); return merged, inv_l + inv_r + inv_m; _, inv = sort_and_count([3, 1, 2]); print(inv)`?', ARRAY['0', '2', '[2, 1]', '4'], '2', 1500, 90.0) ON CONFLICT DO NOTHING;
